function itemUoms(product:Row|undefined):Row[]{
  const stockUom=text(product,"stock_uom"),seen=new Set<string>(),valid:Row[]=[];
  for(const entry of list(product?.uoms)){
    const uom=text(entry,"uom"),factor=Number(entry.conversion_factor);
    if(!uom||seen.has(uom)||!Number.isFinite(factor)||factor<=0)continue;
    seen.add(uom);valid.push(entry);
  }
  if(stockUom&&!seen.has(stockUom))valid.unshift({uom:stockUom,conversion_factor:1,rate:Number(product?.rate)||0,available_qty:Number(product?.available_qty)||0});
  return valid;
}
function defaultItemUom(product:Row|undefined):string{const uoms=itemUoms(product),preferred=text(product,"default_uom","stock_uom");return uoms.some((entry)=>text(entry,"uom")===preferred)?preferred:text(uoms[0],"uom")||preferred||"Nos"}
