  return `<section class="page order-page"><div class="page-title"><div><p class="eyebrow">Customer order</p><h1>Build the order</h1><p>${esc(currentCustomerName())} · ${esc(text(customer||undefined,"price_list")||"Customer pricing")}</p></div><button class="cart-pill" data-open-cart><span>${draft.items.length}</span> Review order</button></div>${customerSummary()}<div class="order-context">${branchControl}${warehouseControl}<label>Delivery date<input id="delivery" type="date" value="${esc(draft.deliveryDate)}"></label></div><div class="catalog-command"><form id="item-form" class="search-bar"><span>⌕</span><input id="item-query" type="search" value="${esc(itemQuery)}" placeholder="Search item, code, category or brand" autocomplete="off">${voiceSearchAvailable()?`<button id="voice-item" type="button" class="voice-search" aria-label="Search items by voice">◉</button>`:""}<button id="scan" type="button" aria-label="Scan barcode">▣ Scan</button></form><div class="view-toggle" aria-label="Catalogue view"><button data-catalog-view="fast" aria-pressed="${catalogView==="fast"}">☷ <span>Fast</span></button><button data-catalog-view="cards" aria-pressed="${catalogView==="cards"}">▦ <span>Cards</span></button></div></div>${!itemQuery?searchHistory(itemSearchHistoryKey,"item"):""}${assortmentConfigured?`<div class="assortment-filter"><button data-assortment-filter aria-pressed="${assortmentOnly}"><span>★</span><b>${esc(currentCustomerName())}'s Products</b><small>${assortmentRuleCount} configured rule${assortmentRuleCount===1?"":"s"}</small></button></div>`:""}<div class="filter-row"><span>Category</span><div class="category-tabs">${categories.map((value)=>`<button data-category="${esc(value)}" ${value===category?'aria-selected="true"':""}>${esc(value)}</button>`).join("")}</div></div>${brands.length>1?`<div class="filter-row"><span>Brand</span><div class="brand-tabs">${brands.map((value)=>`<button data-brand="${esc(value)}" ${value===brandFilter?'aria-selected="true"':""}>${esc(value)}</button>`).join("")}</div></div>`:""}${recent.length?`<div class="recent-row"><span>Recent</span>${recent.map((code)=>`<button class="recent-chip" data-item-search="${esc(code)}">${esc(code)}</button>`).join("")}</div>`:""}<div class="catalog-heading"><div><h2>${catalogView==="fast"?"Fast order":"Product catalogue"}</h2><small>${visible.length} result${visible.length===1?"":"s"} · ${assortmentOnly?"Customer assortment":"Full permitted catalogue"} · ERPNext pricing</small></div>${catalogView==="fast"?`<small class="fast-hint">Change quantities directly—your draft saves automatically</small>`:""}</div><div class="product-grid ${catalogView==="fast"?"fast-order-list":""}">${visible.map(catalogView==="fast"?fastOrderRow:productCard).join("")||emptyState("⌕","No items to show","Search the permitted catalogue or change the category/brand filters.")}</div></section><button class="cart-dock" data-open-cart><span><b>${draft.items.reduce((sum,item)=>sum+item.qty,0)} units · ${draft.items.length} lines</b><small>${draft.status==="queued"?"Queued offline":"Draft saved on this device"}</small></span><strong>${money(estimate())}</strong><span>Review →</span></button>`
