  loading=`Cancelling ${name}`;orderDetail=null;render("orders");
  try{await payload(await api!.cancelOrder(name));notice(`${name} cancelled in ERPNext.`,"success");await loadOrders()}
  catch(error){loading="";notice(error instanceof Error?error.message:"Unable to cancel order","danger");render("orders")}
