  return `<section class="manager-approval-panel" aria-label="Pending discount approvals"><div class="manager-approval-head"><div><p class="eyebrow">Manager queue</p><h2>${discountApprovals.length} discount approval${discountApprovals.length===1?"":"s"}</h2></div><span>ERPNext enforced</span></div><div class="approval-card-grid">${discountApprovals.map((row)=>`<article class="approval-card"><div><strong>${esc(text(row,"sales_order"))}</strong><small>${esc(text(row,"customer_name","customer"))} · Requested by ${esc(text(row,"requested_by"))}</small></div><b>${quantityText(row.requested_percent)}%</b><p>${esc(text(row,"reason"))}</p><span>Order total ${formatMoney(row.grand_total,text(row,"currency")||currency())}</span><div><button class="secondary" data-reject-discount="${esc(text(row,"sales_order"))}">Reject</button><button class="primary" data-approve-discount="${esc(text(row,"sales_order"))}">Approve</button></div></article>`).join("")}</div></section>`
