    const operation:VisitOperation={requestId:newVisitRequestId(),action,visitId,customer:text(visit,"customer"),scheduledDate:text(visit,"scheduled_date")||visitDate,branch:draft.branch||undefined,warehouse:draft.warehouse||text(context,"warehouse")||undefined,notes,photos,queuedAt:new Date().toISOString(),...location};
