function addProduct(code:string,delta=1){const product=itemIndex.get(code)||products.find((entry)=>text(entry,"name","item_code")===code);if(!product)return;const old=draft.items.find((entry)=>entry.item_code===code),selected=selectedUoms.get(code);const uom=old?.uom||(itemUoms(product).some((entry)=>text(entry,"uom")===selected)?selected:defaultItemUom(product));draft=setDraftItem(draft,{item_code:code,qty:(old?.qty||0)+delta,uom});save(draft);preview=null;remember(recentItemsKey,code);notice(delta>0?`${text(product,"item_name","name")} added`:"Quantity updated","success");render(screen)}
